import json

TOOLS = [
    {
        'name': 'search_docs',
        'description': 'Search the project documentation for information',
        'parameters': {'query': 'string'},
    },
    {
        'name': 'read_file',
        'description': 'Read the contents of a file in the project',
        'parameters': {'path': 'string'},
    },
    {
        'name': 'run_snippet',
        'description': 'Execute a short Python snippet and return the output',
        'parameters': {'code': 'string'},
    },
]

def search_docs(query):
    # In production: vector search over documentation
    return 'Found 3 results for: ' + query

def read_file(path):
    try:
        with open(path) as f:
            return f.read()[:2000]
    except FileNotFoundError:
        return 'File not found: ' + path

def run_snippet(code):
    # WARNING: only run trusted code in a sandboxed environment
    try:
        exec_globals = {}
        exec(code, exec_globals)
        return 'OK'
    except Exception as e:
        return 'Error: ' + str(e)

TOOL_FNS = {'search_docs': search_docs, 'read_file': read_file, 'run_snippet': run_snippet}

def chat_assistant(llm_call, user_message, history):
    history.append({'role': 'user', 'content': user_message})
    for _ in range(5):  # max 5 tool calls per turn
        response = llm_call(history, tools=TOOLS)
        tool_call = response.get('tool')
        if not tool_call:
            # Final text response
            history.append({'role': 'assistant', 'content': response['text']})
            return response['text'], history
        # Execute the tool and loop
        fn = TOOL_FNS.get(tool_call['name'])
        result = fn(**tool_call.get('args', {})) if fn else 'Unknown tool'
        history.append({'role': 'tool', 'name': tool_call['name'], 'content': result})
    return 'Could not complete in 5 steps', history

from dataclasses import dataclass, field
import json

@dataclass
class UserProfile:
    preferred_language: str = 'python'
    verbosity: str = 'concise'   # 'concise' | 'detailed'
    include_type_hints: bool = True
    accepted_suggestions: list = field(default_factory=list)
    rejected_patterns: list = field(default_factory=list)

    def to_system_addendum(self):
        lines = [
            'User preferences:',
            '- Language: ' + self.preferred_language,
            '- Response style: ' + self.verbosity,
            '- Include type hints: ' + str(self.include_type_hints),
        ]
        if self.rejected_patterns:
            lines.append('- Avoid: ' + ', '.join(self.rejected_patterns[:5]))
        return '\n'.join(lines)

    def record_feedback(self, suggestion_text, accepted):
        if accepted:
            self.accepted_suggestions.append(suggestion_text[:100])
        else:
            # Extract pattern from rejection for future avoidance
            self.rejected_patterns.append(suggestion_text[:50])

    def save(self, path):
        with open(path, 'w') as f:
            json.dump(vars(self), f, indent=2)

    @classmethod
    def load(cls, path):
        try:
            with open(path) as f:
                return cls(**json.load(f))
        except FileNotFoundError:
            return cls()

profile = UserProfile(preferred_language='python', verbosity='concise', include_type_hints=True)
print(profile.to_system_addendum())

# After user rejects a suggestion with global variables:
profile.record_feedback('global cache = {}', accepted=False)
print('Rejected patterns:', profile.rejected_patterns)
